const cfg = $('Config').first().json;
const webhookItem = $('Webhook Portal Juruá').first();
const body = webhookItem.json?.body ?? webhookItem.json ?? {};
const headers = webhookItem.json?.headers ?? {};

// Validar segredo
const reqSecret = body.secret || headers['x-n8n-secret'] || headers['x-portal-secret'] || '';
if (cfg.portalSecret && reqSecret && reqSecret !== cfg.portalSecret) {
  throw new Error('Segredo inválido no upload.');
}

const livroId = String(body.itemId || body.livroId || body.id || '');
if (!livroId) throw new Error('livroId obrigatório.');

const portalCallbackUrl = body.portalCallbackUrl || '';

let fileBin = null;
const binaries = webhookItem.binary || {};
const firstBinaryKey = Object.keys(binaries)[0];
if (firstBinaryKey) {
  fileBin = binaries[firstBinaryKey];
}

if (!fileBin) {
  const b64raw = body.fileBase64 || body.file_base64 || body.data || '';
  if (b64raw) {
    const b64clean = b64raw.replace(/^data:[^;]+;base64,/, '');
    const fileName = body.fileName || body.file_name || `jurua-${livroId}.pdf`;
    fileBin = { data: b64clean, mimeType: 'application/pdf', fileName, fileExtension: 'pdf' };
  }
}

if (!fileBin) throw new Error('Nenhum PDF recebido.');

const title = String(body.title || body.titulo || fileBin.fileName || 'livro')
  .replace(/\.pdf$/i, '').trim();

const safeSlug = title.normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-zA-Z0-9_-]+/g, '-').replace(/-+/g, '-')
  .replace(/^-|-$/g, '').toLowerCase() || 'livro';

return [{
  json: { ...cfg, livroId, portalCallbackUrl, wpTitle: title, safeSlug,
    sourcePdfFileName: `jurua-${livroId}-${safeSlug}.pdf`,
    uploadStartedAt: new Date().toISOString() },
  binary: { pdf: fileBin }
}];

const src = $input.first(); const cfg = $('Config').first().json;
const base = $('Normalizar Upload').first().json;
const body = src.json || {};
const parsed = Array.isArray(body.ParsedResults) ? body.ParsedResults : [];
const rawText = parsed.map(p => p.ParsedText || '').join('\n\n');
const cleanText = String(rawText || '').replace(/\r/g, '\n').replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n').replace(/Página \d+/gi, '').replace(/\u0000/g, '').trim();
const charCount = cleanText.length;
if (charCount < cfg.minExtractedCharsThreshold) {
  throw new Error(`Texto insuficiente: ${charCount} chars. Verifique o PDF.`);
}
return [{ json: { ...cfg, ...base, narrationText: cleanText, charCount,
  wordCount: cleanText.split(/\s+/).length, driveFileId: $('Drive Upload PDF').first().json.id } }];

const item = $input.first().json;
const text = String(item.narrationText || '').trim();
const maxChars = Number(item.maxCharsPerEpisode || 5000);
const minChars = Number(item.minCharsPerEpisode || 1200);
const sentenceRegex = /[^.!?\n]+[.!?\n]*/g;
const sentences = text.match(sentenceRegex) || [text];
const episodes = [];
let current = '';
for (const sentence of sentences) {
  if ((current + sentence).length > maxChars && current.length >= minChars) {
    episodes.push(current.trim());
    current = sentence;
  } else { current += sentence; }
}
if (current.trim()) {
  if (episodes.length > 0 && current.length < minChars) episodes[episodes.length - 1] += ' ' + current.trim();
  else episodes.push(current.trim());
}
const total = episodes.length;
return episodes.map((epText, idx) => {
  const ep = String(idx + 1).padStart(2, '0');
  const slug = item.safeSlug || 'livro';
  const imageCount = Math.max(1, Math.ceil((epText.length / 1000) * 60 / Number(item.secondsPerImage || 45)));
  const epTitulo = `${item.wpTitle} — Episódio ${idx + 1}`;
  return { json: { ...item, episodeNumber: idx + 1, episodeFormatted: ep, totalEpisodes: total,
    episodeText: epText, episodeChars: epText.length, episodeTitulo: epTitulo, imageCount,
    audiobookFileName: `${slug}_ep-${ep}_audiobook.mp3`,
    videoFileName: `${slug}_ep-${ep}_video.mp4`,
    slidesFileName: `${slug}_ep-${ep}_slides.md`,
    thumbFileName: `${slug}_ep-${ep}_thumb.png` } };
});

