const item = $input.first().json;
try {
  const content = item.choices?.[0]?.message?.content || '{"perguntas":[]}';
  const parsed = JSON.parse(content);
  const perguntas = parsed.perguntas || [];
  return [{ json: { ...item, quizPerguntas: perguntas, quizOk: perguntas.length > 0 } }];
} catch (e) {
  return [{ json: { ...item, quizPerguntas: [], quizOk: false, quizError: e.message } }];
}
